class Solution:
    def splitIntoFibonacci(self, num: str) -> List[int]:
        n = len(num)
        for i in range(1, n):
            for j in range(i+1, n):
                a_str = num[:i]
                b_str = num[i:j]
                if (len(a_str) > 1 and a_str[0] == '0') or (len(b_str) > 1 and b_str[0] == '0'):
                    continue
                try:
                    a = int(a_str)
                    b = int(b_str)
                except:
                    continue
                if a >= 2**31 or b >= 2**31:
                    continue
                seq = [a, b]
                pos = j
                valid = True
                while pos < n:
                    nxt = seq[-1] + seq[-2]
                    if nxt >= 2**31:
                        valid = False
                        break
                    nxt_str = str(nxt)
                    if not num.startswith(nxt_str, pos):
                        valid = False
                        break
                    seq.append(nxt)
                    pos += len(nxt_str)
                if valid and len(seq) >= 3 and pos == n:
                    return seq
        return []

